import { Component, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { CartService } from '../../core/services/cart.service';
import { MoneyPipe } from '../../shared/money.pipe';

const FREE_SHIP_THRESHOLD = 7500;
const SHIP_FEE = 599;

@Component({
  selector: 'app-cart',
  standalone: true,
  imports: [CommonModule, RouterLink, MoneyPipe],
  templateUrl: './cart.component.html',
  styleUrls: ['./cart.component.css'],
})
export class CartComponent {
  cart = inject(CartService);

  readonly shippingCents = computed(() =>
    this.cart.subtotalCents() === 0 || this.cart.subtotalCents() >= FREE_SHIP_THRESHOLD
      ? 0
      : SHIP_FEE,
  );
  readonly totalCents = computed(() => this.cart.subtotalCents() + this.shippingCents());

  inc(itemId: string, qty: number): void {
    this.cart.updateQuantity(itemId, qty + 1);
  }
  dec(itemId: string, qty: number): void {
    this.cart.updateQuantity(itemId, qty - 1);
  }
  remove(itemId: string): void {
    this.cart.removeItem(itemId);
  }
}
